import{c as o,Q as n,j as i,g as e,n as t}from"./chunks/framework.hhGiamYR.js";const f=JSON.parse('{"title":"CHAPTER VII —_Why it is that changes from Freedom to Servitude, and","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/discourses/en/book1/chapter-vii.md","filePath":"research/machiavelli/machiavelli/discourses/en/book1/chapter-vii.md"}'),s={name:"research/machiavelli/machiavelli/discourses/en/book1/chapter-vii.md"};function h(r,a,d,c,m,l){return n(),i("div",null,[...a[0]||(a[0]=[e("h1",{id:"chapter-vii-—-why-it-is-that-changes-from-freedom-to-servitude-and",tabindex:"-1"},[t("CHAPTER VII —_Why it is that changes from Freedom to Servitude, and "),e("a",{class:"header-anchor",href:"#chapter-vii-—-why-it-is-that-changes-from-freedom-to-servitude-and","aria-label":'Permalink to "CHAPTER VII —_Why it is that changes from Freedom to Servitude, and"'},"​")],-1),e("p",null,[t("CHAPTER VII.—"),e("em",null,"Why it is that changes from Freedom to Servitude, and from Servitude to Freedom, are sometimes made without Bloodshed, but at other times reek with Blood"),t(".")],-1),e("p",null,"Since we find from history that in the countless changes which have been made from freedom to servitude and from servitude to freedom, sometimes an infinite multitude have perished, while at others not a soul has suffered (as when Rome made her change from kings to consuls, on which occasion none was banished save Tarquin, and no harm was done to any other), it may perhaps be asked, how it happens that of these revolutions, some have been attended by bloodshed and others not.",-1),e("p",null,"The answer I take to be this. The government which suffers change either has or has not had its beginning in violence. And since the government which has its beginning in violence must start by inflicting injuries on many, it must needs happen that on its downfall those who were injured will desire to avenge themselves; from which desire for vengeance the slaughter and death of many will result. But when a government originates with, and derives its authority from the whole community, there is no reason why the community, if it withdraw that authority, should seek to injure any except the prince from whom it withdraws it. Now the government of Rome was of this nature, and the expulsion of the Tarquins took place in this way. Of a like character was the government of the Medici in Florence, and, accordingly, upon their overthrow in the year 1494, no injury was done to any save themselves.",-1),e("p",null,"In such cases, therefore, the changes I speak of do not occasion any very great danger. But the changes wrought by men who have wrongs to revenge, are always of a most dangerous kind, and such, to say the least, as may well cause dismay in the minds of those who read of them. But since history abounds with instances of such changes I need say no more about them.",-1)])])}const v=o(s,[["render",h]]);export{f as __pageData,v as default};
